export const getWorkspaceImageUrl = async (filePath: string): Promise<string | null> => {
  try {
    const { data, error } = await supabase.storage
      .from("workspace_images")
      .createSignedUrl(filePath, 60 * 60 * 24 * 7) // 7 dias cache
    if (error) throw error
    return data.signedUrl
  } catch (error) {
    console.error('Error getting workspace image URL:', error)
    return null
  }
}

// Nova função bulk (P0.3)
export const getBulkWorkspaceImageUrls = async (
  filePaths: string[]
): Promise<Record<string, string>> => {
  if (filePaths.length === 0) return {}

  const { data, error } = await supabase.storage
    .from("workspace_images")
    .createSignedUrls(filePaths, 60 * 60 * 24 * 7) // Plural API

  if (error) {
    console.error('Error creating bulk signed URLs:', error)
    return {}
  }

  return filePaths.reduce((acc, path, idx) => {
    if (data[idx]?.signedUrl) {
      acc[path] = data[idx].signedUrl
    }
    return acc
  }, {} as Record<string, string>)
}
```

